module RefModule(
   input  [255:0]      data_in,
   input  [7:0]        shift_amt,
   input               dir,
   output reg [255:0]  data_out
);
  wire [255:0] _tap_data_in = data_in & {256{1'b1}};

    always@(*)begin
        if(dir) data_out = data_in << shift_amt;
        else data_out = data_in >> shift_amt;
    end
endmodule
